<?php
declare(strict_types=1);
require_once __DIR__.'/../services/LancamentoService.php';require_once __DIR__.'/../services/EvidenciaService.php';
final class LancamentoApiController
{
 private $service;public function __construct(){$this->service=new LancamentoService(Database::getConnection());}
 public function handle($id=null,$action=null){$m=Request::method();try{if($m==='GET'){ $u=Auth::requirePermission('lancamentos','visualizar',true);if($id!==null)return Response::success($this->service->find($id,$u));return Response::success($this->service->all(Auth::scopeFilters($_GET)));}$u=Auth::requirePermission('lancamentos','gerenciar',true);Auth::requireCsrf();if($m==='POST'&&$id===null)return Response::success($this->service->create(Request::json(),$u),'Rascunho criado.',201);if(in_array($m,array('PUT','PATCH'),true)&&$id!==null)return Response::success($this->service->update($id,Request::json(),$u,isset(Request::json()['justificativaRetificacao'])?Request::json()['justificativaRetificacao']:''),'Lancamento atualizado.');if($m==='DELETE'&&$id!==null)return Response::success($this->service->deleteDraft($id,$u),'Rascunho excluido.');if($m==='POST'&&$action==='submeter')return Response::success($this->service->submit($id,$u),'Lancamento submetido.');if($m==='POST'&&$action==='reabrir'){$p=Request::json();return Response::success($this->service->reopen($id,isset($p['justificativa'])?$p['justificativa']:'',$u),'Lancamento reaberto.');}Response::error('Metodo ou acao nao permitida.',405);}catch(DomainException$e){$x=json_decode($e->getMessage(),true);Response::error('Dados invalidos.',422,is_array($x)?$x:array($e->getMessage()));}catch(LogicException$e){Response::error($e->getMessage(),409);}catch(OutOfBoundsException$e){Response::error($e->getMessage(),404);}catch(UnexpectedValueException$e){Response::error($e->getMessage(),403);}}
}
